    15→func TestSlackSender_Send(t *testing.T) {
    16→	var received []byte
    17→	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
    18→		if r.Header.Get("Content-Type") != "application/json" {
    19→			t.Errorf("expected Content-Type application/json, got %s", r.Header.Get("Content-Type"))
    20→		}
    21→		received, _ = io.ReadAll(r.Body)
    22→		w.WriteHeader(http.StatusOK)
    23→	}))
    24→	defer srv.Close()
    25→
    26→	sender := &SlackSender{Client: srv.Client()}
    27→	ch := &models.NotificationChannel{
    28→		Type:   "slack",
    29→		Config: json.RawMessage(`{"webhook_url": "` + srv.URL + `"}`),
    30→	}
    31→	msg := Notification{
    32→		Title:   "New release: geth v1.14.0",
    33→		Body:    "Released on GitHub with security fixes",
    34→		Version: "v1.14.0",
    35→	}
    36→
    37→	err := sender.Send(context.Background(), ch, msg)
    38→	if err != nil {
    39→		t.Fatalf("unexpected error: %v", err)
    40→	}
    41→	if len(received) == 0 {
    42→		t.Fatal("expected Slack to receive payload")
    43→	}
    44→
    45→	// Verify it's a valid Slack Block Kit payload with blocks.
    46→	var payload map[string]interface{}
    47→	if err := json.Unmarshal(received, &payload); err != nil {
    48→		t.Fatalf("received invalid JSON: %v", err)
    49→	}
    50→	blocks, ok := payload["blocks"]
    51→	if !ok {
    52→		t.Fatal("expected 'blocks' key in Slack payload")
    53→	}
    54→	blockList, ok := blocks.([]interface{})
    55→	if !ok || len(blockList) < 2 {
    56→		t.Fatalf("expected at least 2 blocks, got %v", blocks)
    57→	}
    58→}
