    12→)
    13→
    14→// discordEmbedDescriptionLimit is Discord's maximum embed description length.
    15→const discordEmbedDescriptionLimit = 4096
    16→
    17→type discordConfig struct {
    18→	WebhookURL string `json:"webhook_url"`
    19→}
    20→
    21→// DiscordSender sends notifications as Discord webhook messages with embeds.
    22→type DiscordSender struct {
    23→	Client *http.Client
    24→}
    25→
    26→// discordPayload is the Discord webhook payload.
    27→type discordPayload struct {
    28→	Embeds []discordEmbed `json:"embeds"`
    29→}
    30→
    31→type discordEmbed struct {
    32→	Title       string              `json:"title"`
    33→	Description string              `json:"description"`
    34→	Color       int                 `json:"color"`
    35→	Fields      []discordEmbedField `json:"fields,omitempty"`
    36→}
    37→
    38→type discordEmbedField struct {
    39→	Name   string `json:"name"`
    40→	Value  string `json:"value"`
    41→	Inline bool   `json:"inline"`
    42→}
    43→
    44→// discordRiskColor returns a Discord embed color based on risk level.
    45→func discordRiskColor(level string) int {
    46→	switch strings.ToUpper(strings.TrimSpace(level)) {
    47→	case "CRITICAL":
    48→		return 0x111113 // near-black
    49→	case "HIGH":
    50→		return 0xDC2626 // red
    51→	case "MEDIUM":
    52→		return 0xD97706 // amber
    53→	case "LOW":
    54→		return 0x16A34A // green
    55→	default:
    56→		return 0x5865F2 // Discord blurple
    57→	}
    58→}
    59→
    60→// buildSemanticEmbed builds a rich Discord embed from a SemanticReport.
    61→func buildSemanticEmbed(title string, version string, report *models.SemanticReport) discordEmbed {
    62→	var descParts []string
    63→
    64→	if report.Subject != "" {
    65→		descParts = append(descParts, fmt.Sprintf("**%s**", report.Subject))
    66→	}
    67→
    68→	if report.RiskReason != "" {
    69→		descParts = append(descParts, fmt.Sprintf(">>> %s", report.RiskReason))
    70→	}
    71→
    72→	if len(report.StatusChecks) > 0 {
    73→		var checks []string
    74→		for _, check := range report.StatusChecks {
    75→			checks = append(checks, fmt.Sprintf("✅ %s", check))
    76→		}
    77→		descParts = append(descParts, strings.Join(checks, "\n"))
    78→	}
    79→
    80→	summary := report.ChangelogSummary
    81→	if summary == "" {
    82→		summary = report.Summary
    83→	}
    84→	if summary != "" {
    85→		descParts = append(descParts, fmt.Sprintf("**Changelog**\n%s", summary))
    86→	}
    87→
    88→	if len(report.DownloadCommands) > 0 {
    89→		descParts = append(descParts, fmt.Sprintf("**Download Commands**\n```\n%s\n```", strings.Join(report.DownloadCommands, "\n")))
    90→	}
    91→
    92→	if len(report.DownloadLinks) > 0 {
    93→		var links []string
    94→		for _, link := range report.DownloadLinks {
    95→			links = append(links, fmt.Sprintf("• %s", link))
    96→		}
    97→		descParts = append(descParts, fmt.Sprintf("**Download Links**\n%s", strings.Join(links, "\n")))
    98→	}
    99→
   100→	description := strings.Join(descParts, "\n\n")
   101→	if len(description) > discordEmbedDescriptionLimit {
   102→		description = description[:discordEmbedDescriptionLimit-3] + "..."
   103→	}
   104→
   105→	fields := []discordEmbedField{
   106→		{Name: "Risk Level", Value: fmt.Sprintf("%s %s", riskEmoji(report.RiskLevel), report.RiskLevel), Inline: true},
   107→		{Name: "Urgency", Value: report.Urgency, Inline: true},
   108→	}
   109→	if report.Availability != "" {
   110→		fields = append(fields, discordEmbedField{Name: "Availability", Value: report.Availability, Inline: true})
   111→	}
   112→	if report.Adoption != "" {
   113→		fields = append(fields, discordEmbedField{Name: "Adoption", Value: report.Adoption, Inline: false})
   114→	}
   115→
   116→	return discordEmbed{
   117→		Title:       title,
   118→		Description: description,
   119→		Color:       discordRiskColor(report.RiskLevel),
   120→		Fields:      fields,
